defmodule SessionPlug do
  @moduledoc """
  Plug for integrating SessionManager with Phoenix/Plug pipelines.
  Reads session from cookie on request, writes updated session on response.
  """

  import Plug.Conn
  @behaviour Plug

  @cookie_name "_app_session"
  @cookie_opts [
    http_only: true,
    secure: true,
    same_site: "Lax",
    max_age: 86_400,
    path: "/"
  ]

  @impl true
  def init(opts) do
    cookie_name = Keyword.get(opts, :cookie_name, @cookie_name)
    cookie_opts = Keyword.merge(@cookie_opts, Keyword.get(opts, :cookie_opts, []))
    %{cookie_name: cookie_name, cookie_opts: cookie_opts}
  end

  @impl true
  def call(conn, %{cookie_name: cookie_name, cookie_opts: cookie_opts}) do
    conn = fetch_cookies(conn)

    session =
      conn.cookies
      |> Map.get(cookie_name)
      |> SessionManager.deserialize!()

    conn
    |> assign(:session, session)
    |> register_before_send(fn conn ->
      session = conn.assigns[:session]

      if session do
        serialized = SessionManager.serialize(session)
        put_resp_cookie(conn, cookie_name, serialized, cookie_opts)
      else
        delete_resp_cookie(conn, cookie_name)
      end
    end)
  end
end

