    expiry = System.system_time(:second) + @session_ttl
    :ets.insert(@table_name, {session_id, binary_data, expiry})

    # Broadcast to other nodes
    broadcast_session_update(session_id, binary_data, expiry)
    :ok
  end

  @doc """
  Retrieves a session from the distributed store.
  """
