    case :ets.lookup(@table_name, session_id) do
      [{^session_id, binary_data, expiry}] ->
        if System.system_time(:second) < expiry do
          session = :erlang.binary_to_term(binary_data, [:safe])
          {:ok, session}
        else
          :ets.delete(@table_name, session_id)
          {:error, :expired}
        end

      [] ->
        # Try fetching from other nodes
        fetch_from_cluster(session_id)
    end
  end

  @doc """
  Removes a session from the distributed store.
  """
  def delete(session_id) do
    :ets.delete(@table_name, session_id)
    broadcast_session_delete(session_id)
    :ok
  end

  # Server callbacks

  @impl true
  def init(_opts) do
    table = :ets.new(@table_name, [:named_table, :public, :set, read_concurrency: true])

    # Join the process group for distributed communication
    :pg.start_link()
    :pg.join(:session_managers, self())

    schedule_cleanup()
    {:ok, %{table: table}}
  end

  @impl true
  def handle_info(:cleanup, state) do
