    :ets.insert(@table_name, {session_id, binary_data, expiry})
    {:noreply, state}
  end

  @impl true
  def handle_info({:session_delete, session_id}, state) do
    :ets.delete(@table_name, session_id)
    {:noreply, state}
  end

