    {:noreply, state}
  end

  @impl true
  def handle_info(_, state), do: {:noreply, state}

  # Private functions

  defp schedule_cleanup do
    Process.send_after(self(), :cleanup, @cleanup_interval)
  end

  defp broadcast_session_update(session_id, binary_data, expiry) do
    members = :pg.get_members(:session_managers) -- [self()]

    Enum.each(members, fn pid ->
      send(pid, {:session_update, session_id, binary_data, expiry})
    end)
